//! movement.rs reads movement keys and advances the player each frame, resolving
//! collisions against the world. All speeds are expressed per second and scaled by
//! delta time so movement is frame-rate independent.
//!
//! The three control axes are generated by the [`axis!`](crate::macros::axis)
//! macro, which gives each a `sample` (read the keyboard) and a `signum` (turn the
//! direction into a scalar for vector math).
use raylib::prelude::*;

use crate::macros::axis;
use crate::math::Aabb;
use crate::player::{PLAYER_HALF, Player};
use crate::world::World;

const WALK_SPEED: f32 = 6.0; // units / second on the ground
const FLY_SPEED: f32 = 14.0; // units / second while flying
const GRAVITY: f32 = 24.0; // units / second^2
const JUMP_SPEED: f32 = 8.5; // initial upward velocity of a jump

axis!(AxisZ { Forward = KEY_W, Backward = KEY_S });
axis!(AxisX { Right = KEY_D, Left = KEY_A });
axis!(AxisY { Up = KEY_SPACE, Down = KEY_LEFT_SHIFT });

/// The movement intent gathered from the keyboard for a single frame.
pub struct MoveInput {
    forward_back: AxisZ,
    left_right: AxisX,
    up_down: AxisY,
    jump: bool,
    toggle_fly: bool,
}

impl MoveInput {
    /// Sample the keyboard into a `MoveInput` for this frame.
    pub fn sample(rl: &RaylibHandle) -> Self {
        Self {
            forward_back: AxisZ::sample(rl),
            left_right: AxisX::sample(rl),
            up_down: AxisY::sample(rl),
            jump: rl.is_key_down(KeyboardKey::KEY_SPACE),
            toggle_fly: rl.is_key_pressed(KeyboardKey::KEY_F),
        }
    }
}

/// Advance the player by one frame: build a movement delta from input + physics,
/// then apply it with per-axis collision resolution.
pub fn update_player(player: &mut Player, world: &World, input: &MoveInput, dt: f32) {
    if input.toggle_fly {
        player.fly = !player.fly;
        player.velocity_y = 0.0;
    }

    // Horizontal movement is relative to where the player is facing. The axis
    // signums collapse the direction enums into a single weighted sum.
    let forward = player.forward_flat();
    let right = player.right_flat();
    let mut horizontal =
        forward.scale(input.forward_back.signum()) + right.scale(input.left_right.signum());
    // Normalize so moving diagonally isn't faster than moving straight.
    if horizontal.length() > 0.0 {
        horizontal = horizontal.normalize();
    }

    let speed = if player.fly { FLY_SPEED } else { WALK_SPEED };
    let mut delta = horizontal.scale(speed * dt);

    if player.fly {
        // Free vertical movement, no gravity.
        delta.y += input.up_down.signum() * speed * dt;
        player.velocity_y = 0.0;
    } else {
        // Integrate gravity, and jump only when grounded.
        if input.jump && player.on_ground {
            player.velocity_y = JUMP_SPEED;
        }
        player.velocity_y -= GRAVITY * dt;
        delta.y += player.velocity_y * dt;
    }

    move_with_collision(player, world, delta);
}

/// Apply `delta` one axis at a time so the player slides along walls instead of
/// sticking, and detects when they land on the ground.
fn move_with_collision(player: &mut Player, world: &World, delta: Vector3) {
    let start = player.position;
    let mut pos = start;

    // X axis.
    pos.x += delta.x;
    if world.collides(&Aabb::new(pos, PLAYER_HALF)) {
        pos.x = start.x;
    }

    // Z axis.
    pos.z += delta.z;
    if world.collides(&Aabb::new(pos, PLAYER_HALF)) {
        pos.z = start.z;
    }

    // Y axis: landing on something while moving down means we're grounded.
    player.on_ground = false;
    pos.y += delta.y;
    if world.collides(&Aabb::new(pos, PLAYER_HALF)) {
        if delta.y < 0.0 {
            player.on_ground = true;
        }
        pos.y = start.y;
        player.velocity_y = 0.0;
    }

    player.position = pos;
}
